/**
 * Wire-nav step of the two-pass populate pattern. Walks every Country's
 * `currencies` list and back-fills each Currency's `acceptedInCountries`
 * + `acceptedInCountryIso31661Alpha2Codes` reverse navs.
 */
export function wireCurrencyNav(): void {
  const accumulator = new Map<CurrencyCode, Country[]>();
  for (const country of CountryLookup.all) {
    for (const cc of country.currencies) {
      let list = accumulator.get(cc.iso4217AlphaCode);
      if (list === undefined) { list = []; accumulator.set(cc.iso4217AlphaCode, list); }
      list.push(country);
    }
  }
  for (const [code, countries] of accumulator) {
    const rec = CurrencyLookup.byCode[code];
    if (rec === undefined) continue;
    const mut = rec as { -readonly [K in keyof Currency]: Currency[K] };
    mut.acceptedInCountries = countries;
    const codeSet = new Set<CountryCode>();
    for (const c of countries) codeSet.add(c.iso31661Alpha2Code);
    mut.acceptedInCountryIso31661Alpha2Codes = codeSet;
  }
}
